-			name == "var" || name == "usr" || name == "lib" || name == "lib64" ||
-			name == "bin" || name == "sbin" || name == "boot" || name == "etc" ||
-			name == "snap" || name == "mnt" || name == "media" || name == "srv" ||
-			name == "opt" || name == "tmp" || name == "root" || name == "home" {
-			continue
-		}
-
-		fullPath := filepath.Join(parent, name)
